前置条件:
sql语句列表：
ddl：
-- 创建表（带 COMMENT 和 TBLPROPERTIES）
CREATE TABLE IF NOT EXISTS sales_orders (
order_id     STRING COMMENT &#039;订单ID&#039;,
customer_id  STRING COMMENT &#039;客户ID&#039;,
order_date   DATE   COMMENT &#039;订单日期&#039;,
amount       DECIMAL(10,2) COMMENT &#039;订单金额&#039;
)
USING parquet
PARTITIONED BY (order_date)
TBLPROPERTIES (&#039;comment&#039; = &#039;销售订单表&#039;);
-- 修改表结构（新增字段）
ALTER TABLE sales_orders
ADD COLUMNS (status STRING COMMENT &#039;订单状态&#039;);
-- 删除表
DROP TABLE IF EXISTS sales_orders;
dql：
-- 简单查询
SELECT * FROM sales_orders WHERE amount &gt; 100;
-- 窗口函数
SELECT customer_id,
SUM(amount) OVER (PARTITION BY customer_id ORDER BY order_date) AS running_total
FROM sales_orders;
-- GROUPING SETS（Spark 3.5 增强）
SELECT customer_id, order_date, SUM(amount) AS total
FROM sales_orders
GROUP BY GROUPING SETS ((customer_id), (order_date));
dml：
-- 插入数据
INSERT INTO sales_orders
VALUES (&#039;O1001&#039;, &#039;C001&#039;, DATE&#039;2025-01-01&#039;, 199.99, &#039;PAID&#039;);
-- 覆盖插入
INSERT OVERWRITE sales_orders
VALUES (&#039;O1002&#039;, &#039;C002&#039;, DATE&#039;2025-01-02&#039;, 299.50, &#039;PENDING&#039;);
-- 更新数据（Spark 3.1 引入 Delta 支持 UPDATE，3.5 中已稳定）
UPDATE sales_orders
SET status = &#039;CANCELLED&#039;
WHERE order_id = &#039;O1002&#039;;
-- 删除数据
DELETE FROM sales_orders
WHERE amount &lt; 100;
3.5新增sql：
SELECT order_id, order_date + INTERVAL &#039;2&#039; DAY AS new_date
FROM sales_orders;

